function user_file_upload_init() {
    // Create directory if it doesn't exist
    if (!file_exists(WP_CONTENT_DIR . '/uploads/user-files')) {
        mkdir(WP_CONTENT_DIR . '/uploads/user-files', 0777, true);
    }
}

add_action('init', 'user_file_upload_init');

function user_file_upload_form() {
?>
    <form action="<?php echo admin_url('admin-post.php'); ?>" method="post" enctype="multipart/form-data">
        <?php wp_nonce_field('upload_user_files'); ?>
        <input type="file" name="files[]" multiple>
        <button type="submit">Upload Files</button>
    </form>
<?php
}

function user_file_upload_handler() {
    if (isset($_FILES['files'])) {
        $allowed_types = array(
            'image/jpeg',
            'image/png',
            'application/pdf',
            'application/msword',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
        );

        foreach ($_FILES['files']['tmp_name'] as $key => $value) {
            if (in_array($_FILES['files']['type'][$key], $allowed_types)) {
                move_uploaded_file($_FILES['files']['tmp_name'][$key], WP_CONTENT_DIR . '/uploads/user-files/' . $_FILES['files']['name'][$key]);
            } else {
                wp_die('Invalid file type');
            }
        }

        // Save uploaded files to database (assuming you have a custom table)
        global $wpdb;
        foreach ($_FILES['files']['name'] as $file_name) {
            $wpdb->insert($wpdb->prefix . 'user_files', array(
                'file_name' => $file_name,
                'uploaded_by' => get_current_user_id(),
                'upload_date' => current_time('mysql')
            ));
        }
    }

    wp_redirect(admin_url());
}

add_action('admin_post_upload_user_files', 'user_file_upload_handler');